chart.config_raw:
const ctx = document.getElementById('salcChart').getContext('2d');
new Chart(ctx, {
  type: 'bar',
  data: {
    labels: ['Req → Arch', 'Arch → Code', 'Code → Arch', 'Req → Arch → Code', 'Arch → Arch'],
    datasets: [{
      label: '% of studies',
      data: [40, 32, 13, 12, 3],
      backgroundColor: ['#4dabf7', '#f6ad55', '#51cf66', '#fab005', '#ff6b6b'],
      borderRadius: 6,
      maxBarThickness: 64
    }]
  },
  options: {
    animation: false,
    indexAxis: 'y',
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: {
        callbacks: {
          label: function(context) { return context.parsed.x + '%'; }
        }
      }
    },
    scales: {
      x: {
        beginAtZero: true,
        max: 50,
        ticks: {
          callback: function(v) { return v + '%'; },
          color: '#718096',
          font: { size: 12 }
        },
        grid: { color: '#e2e8f0' }
      },
      y: {
        ticks: {
          color: '#4a5568',
          font: { size: 13, weight: '600' }
        },
        grid: { display: false }
      }
    }
  }
});
